class AppConfiguration {
  final String apiBaseUrl;
  final int cacheExpirationMinutes;
  final bool maintenanceMode;
  final String minimumAppVersion;
  final Map<String, bool> featureFlags;
  final DateTime lastFetched;

  AppConfiguration({
    required this.apiBaseUrl,
    this.cacheExpirationMinutes = 30,
    this.maintenanceMode = false,
    this.minimumAppVersion = '1.0.0',
    this.featureFlags = const {},
    required this.lastFetched,
  });

  Map<String, dynamic> toJson() => {
        'apiBaseUrl': apiBaseUrl,
        'cacheExpirationMinutes': cacheExpirationMinutes,
        'maintenanceMode': maintenanceMode,
        'minimumAppVersion': minimumAppVersion,
        'featureFlags': featureFlags,
        'lastFetched': lastFetched.toIso8601String(),
      };

  factory AppConfiguration.fromJson(Map<String, dynamic> json) =>
      AppConfiguration(
        apiBaseUrl: json['apiBaseUrl'] as String,
        cacheExpirationMinutes: json['cacheExpirationMinutes'] as int? ?? 30,
        maintenanceMode: json['maintenanceMode'] as bool? ?? false,
        minimumAppVersion: json['minimumAppVersion'] as String? ?? '1.0.0',
        featureFlags:
            Map<String, bool>.from(json['featureFlags'] as Map? ?? {}),
        lastFetched: DateTime.parse(json['lastFetched'] as String),
      );

  bool isExpired() {
    return DateTime.now().difference(lastFetched).inMinutes >
        cacheExpirationMinutes;
  }
}

class CachedContent {
  final String key;
  final String data;
  final DateTime cachedAt;
  final Duration ttl;

  CachedContent({
    required this.key,
    required this.data,
    required this.cachedAt,
    this.ttl = const Duration(minutes: 30),
  });

  bool get isExpired => DateTime.now().difference(cachedAt) > ttl;

  Map<String, dynamic> toJson() => {
        'key': key,
        'data': data,
        'cachedAt': cachedAt.toIso8601String(),
        'ttlSeconds': ttl.inSeconds,
      };

  factory CachedContent.fromJson(Map<String, dynamic> json) => CachedContent(
        key: json['key'] as String,
        data: json['data'] as String,
        cachedAt: DateTime.parse(json['cachedAt'] as String),
        ttl: Duration(seconds: json['ttlSeconds'] as int? ?? 1800),
      );
}

