class CacheManager {
  static const String _cachePrefix = 'cache_';
  static const String _cacheIndexKey = 'cache_index';
  static const String _userProfileCacheKey = 'cache_user_profile';
  static const String _appConfigCacheKey = 'cache_app_config';

  SharedPreferences? _prefs;

  Future<SharedPreferences> get _preferences async {
    _prefs ??= await SharedPreferences.getInstance();
    return _prefs!;
  }

  // ---- Generic Cache Operations ----

  Future<void> cacheData(String key, String data,
      {Duration ttl = const Duration(minutes: 30)}) async {
    final prefs = await _preferences;
    final cached = CachedContent(
      key: key,
      data: data,
      cachedAt: DateTime.now(),
      ttl: ttl,
    );
    await prefs.setString('$_cachePrefix$key', jsonEncode(cached.toJson()));
    await _addToIndex(key);
  }

  Future<String?> getCachedData(String key) async {
    final prefs = await _preferences;
    final raw = prefs.getString('$_cachePrefix$key');
    if (raw == null) return null;

    try {
      final cached = CachedContent.fromJson(jsonDecode(raw));
      if (cached.isExpired) {
        await removeCachedData(key);
        return null;
      }
      return cached.data;
    } catch (e) {
      debugPrint('CacheManager: Error reading cache for key=$key: $e');
      await removeCachedData(key);
      return null;
    }
  }

  Future<void> removeCachedData(String key) async {
    final prefs = await _preferences;
    await prefs.remove('$_cachePrefix$key');
    await _removeFromIndex(key);
  }

  // ---- User Profile Cache (non-sensitive display data only) ----
  // NOTE: The user profile stored here contains only display-safe data
  // (display name, avatar URL). Sensitive identifiers are in secure storage.

  Future<void> cacheUserProfile(UserProfile profile) async {
    final prefs = await _preferences;
    // Store only non-sensitive display data
    final displayData = {
      'id': profile.id, // public-facing user ID, not a secret
      'displayName': profile.displayName,
      'avatarUrl': profile.avatarUrl,
      'lastUpdated': profile.lastUpdated.toIso8601String(),
      // NOTE: email is intentionally excluded from cache as it's PII
    };
    final cached = CachedContent(
      key: _userProfileCacheKey,
      data: jsonEncode(displayData),
      cachedAt: DateTime.now(),
      ttl: const Duration(hours: 1),
    );
    await prefs.setString(
        _userProfileCacheKey, jsonEncode(cached.toJson()));
  }

  Future<UserProfile?> getCachedUserProfile() async {
    final prefs = await _preferences;
    final raw = prefs.getString(_userProfileCacheKey);
    if (raw == null) return null;

    try {
      final cached = CachedContent.fromJson(jsonDecode(raw));
      if (cached.isExpired) {
        await clearUserProfileCache();
        return null;
      }
      final data = jsonDecode(cached.data) as Map<String, dynamic>;
      return UserProfile(
        id: data['id'] as String,
        displayName: data['displayName'] as String,
        email: '', // Not stored in cache for privacy
        avatarUrl: data['avatarUrl'] as String?,
        lastUpdated: DateTime.parse(data['lastUpdated'] as String),
      );
    } catch (e) {
      debugPrint('CacheManager: Error reading user profile cache: $e');
      await clearUserProfileCache();
      return null;
    }
  }

  Future<void> clearUserProfileCache() async {
    final prefs = await _preferences;
    await prefs.remove(_userProfileCacheKey);
  }

  // ---- App Configuration Cache ----

  Future<void> cacheAppConfiguration(AppConfiguration config) async {
    final prefs = await _preferences;
    final cached = CachedContent(
      key: _appConfigCacheKey,
      data: jsonEncode(config.toJson()),
      cachedAt: DateTime.now(),
      ttl: Duration(minutes: config.cacheExpirationMinutes),
    );
    await prefs.setString(
        _appConfigCacheKey, jsonEncode(cached.toJson()));
  }

  Future<AppConfiguration?> getCachedAppConfiguration() async {
    final prefs = await _preferences;
    final raw = prefs.getString(_appConfigCacheKey);
    if (raw == null) return null;

    try {
      final cached = CachedContent.fromJson(jsonDecode(raw));
      if (cached.isExpired) {
        await clearAppConfigCache();
        return null;
      }
      return AppConfiguration.fromJson(jsonDecode(cached.data));
    } catch (e) {
      debugPrint('CacheManager: Error reading app config cache: $e');
      await clearAppConfigCache();
      return null;
    }
  }

  Future<void> clearAppConfigCache() async {
    final prefs = await _preferences;
    await prefs.remove(_appConfigCacheKey);
  }

  // ---- Cache JSON objects ----

  Future<void> cacheJson(String key, Map<String, dynamic> json,
      {Duration ttl = const Duration(minutes: 30)}) async {
    await cacheData(key, jsonEncode(json), ttl: ttl);
  }

  Future<Map<String, dynamic>?> getCachedJson(String key) async {
    final data = await getCachedData(key);
    if (data == null) return null;
    try {
      return jsonDecode(data) as Map<String, dynamic>;
    } catch (e) {
      debugPrint('CacheManager: Error decoding JSON for key=$key: $e');
      return null;
    }
  }

  // ---- Cache list of JSON objects ----

  Future<void> cacheJsonList(String key, List<Map<String, dynamic>> list,
      {Duration ttl = const Duration(minutes: 30)}) async {
    await cacheData(key, jsonEncode(list), ttl: ttl);
  }

  Future<List<Map<String, dynamic>>?> getCachedJsonList(String key) async {
    final data = await getCachedData(key);
    if (data == null) return null;
    try {
      final decoded = jsonDecode(data) as List;
      return decoded.cast<Map<String, dynamic>>();
    } catch (e) {
      debugPrint('CacheManager: Error decoding JSON list for key=$key: $e');
      return null;
    }
  }

  // ---- Cache Index Management ----

  Future<void> _addToIndex(String key) async {
    final prefs = await _preferences;
    final index = prefs.getStringList(_cacheIndexKey) ?? [];
    if (!index.contains(key)) {
      index.add(key);
      await prefs.setStringList(_cacheIndexKey, index);
    }
  }

  Future<void> _removeFromIndex(String key) async {
    final prefs = await _preferences;
    final index = prefs.getStringList(_cacheIndexKey) ?? [];
    index.remove(key);
    await prefs.setStringList(_cacheIndexKey, index);
  }

  Future<List<String>> getCacheKeys() async {
    final prefs = await _preferences;
    return prefs.getStringList(_cacheIndexKey) ?? [];
  }

  // ---- Purge expired entries ----

  Future<int> purgeExpired() async {
    final prefs = await _preferences;
    final keys = await getCacheKeys();
    int purgedCount = 0;

    for (final key in keys) {
      final raw = prefs.getString('$_cachePrefix$key');
      if (raw == null) {
        await _removeFromIndex(key);
        purgedCount++;
        continue;
      }
      try {
        final cached = CachedContent.fromJson(jsonDecode(raw));
        if (cached.isExpired) {
          await removeCachedData(key);
          purgedCount++;
        }
      } catch (_) {
        await removeCachedData(key);
        purgedCount++;
      }
    }

    debugPrint('CacheManager: Purged $purgedCount expired entries');
    return purgedCount;
  }

  // ---- Clear all cached content ----

  Future<void> clearAll() async {
    final prefs = await _preferences;
    final keys = await getCacheKeys();

    for (final key in keys) {
      await prefs.remove('$_cachePrefix$key');
    }
    await prefs.remove(_cacheIndexKey);
    await prefs.remove(_userProfileCacheKey);
    await prefs.remove(_appConfigCacheKey);
  }
}

// ============================================================================
// Unified Local Storage Manager — facade over all storage layers
// ============================================================================

class LocalStorageManager {
  static LocalStorageManager? _instance;

  final SecureStorageManager secure;
  final PreferencesManager preferences;
  final CacheManager cache;

  LocalStorageManager._({
    required this.secure,
    required this.preferences,
    required this.cache,
  });

  factory LocalStorageManager({
    SecureStorageManager? secureStorageManager,
    PreferencesManager? preferencesManager,
    CacheManager? cacheManager,
  }) {
    _instance ??= LocalStorageManager._(
      secure: secureStorageManager ?? SecureStorageManager(),
      preferences: preferencesManager ?? PreferencesManager(),
      cache: cacheManager ?? CacheManager(),
    );
    return _instance!;
  }

  static LocalStorageManager get instance {
    if (_instance == null) {
      throw StateError(
          'LocalStorageManager not initialized. Call LocalStorageManager() first.');
    }
    return _instance!;
  }

  // ---- High-level Auth Operations ----

  /// Save authentication data after login.
  /// Tokens go to secure storage; display profile goes to cache.
  Future<void> onUserLogin({
    required String accessToken,
    required String refreshToken,
    required UserProfile profile,
  }) async {
    // Tokens → secure storage (encrypted, platform-native)
    await secure.saveAuthTokens(
      accessToken: accessToken,
      refreshToken: refreshToken,
      userId: profile.id,
    );

    // Non-sensitive display data → cache
    await cache.cacheUserProfile(profile);

    // Record sync time
    await preferences.setLastSyncTime(DateTime.now());

    debugPrint('LocalStorageManager: User login data saved securely');
  }

  /// Clear all user-related data on logout.
  Future<void> onUserLogout() async {
    await secure.clearAll();
    await cache.clearUserProfileCache();
    await cache.clearAll();
    // Preferences (theme, locale, etc.) are intentionally preserved across logout
    debugPrint('LocalStorageManager: User data cleared on logout');
  }

  /// Check if user is authenticated (has stored tokens).
  Future<bool> isAuthenticated() async {
    return await secure.hasValidAuth();
  }

  /// Get the access token for API calls.
  Future<String?> getAccessToken() async {
    return await secure.getAccessToken();
  }

  /// Get cached user profile for quick UI display.
  Future<UserProfile?> getUserProfile() async {
    return await cache.getCachedUserProfile();
  }

  // ---- High-level Config Operations ----

  /// Get app configuration, returning cached version if available and fresh.
  Future<AppConfiguration?> getAppConfiguration() async {
    return await cache.getCachedAppConfiguration();
  }

  /// Save app configuration to cache after fetching from server.
  Future<void> saveAppConfiguration(AppConfiguration config) async {
    await cache.cacheAppConfiguration(config);
  }

  // ---- Maintenance ----

  /// Purge all expired cache entries.
  Future<int> purgeExpiredCache() async {
    return await cache.purgeExpired();
  }

  /// Full reset — clears everything including preferences.
  Future<void> factoryReset() async {
    await secure.clearAll();
    await cache.clearAll();
    await preferences.clearAll();
    debugPrint('LocalStorageManager: Factory reset complete');
  }

  /// Reset singleton for testing.
  @visibleForTesting
  static void resetInstance() {
    _instance = null;
  }
}

