Future<void> main() async {
  // Initialize the storage manager
  final storage = LocalStorageManager();

  // --- Simulate user login ---
  print('=== Simulating User Login ===');

  await storage.onUserLogin(
    accessToken: 'eyJhbGciOiJSUzI1NiIsInR5cCI6IkpXVCJ9.example_access_token',
    refreshToken: 'dGhpcyBpcyBhIHJlZnJlc2ggdG9rZW4.example_refresh_token',
    profile: UserProfile(
      id: 'user_12345',
      displayName: 'Jane Developer',
      email: 'jane@example.com', // NOTE: email is NOT cached, only in memory
      avatarUrl: 'https://example.com/avatars/jane.png',
      lastUpdated: DateTime.now(),
    ),
  );

  // --- Check authentication ---
  final isAuth = await storage.isAuthenticated();
  print('Is authenticated: $isAuth');

  // --- Get cached profile (fast, no network) ---
  final profile = await storage.getUserProfile();
  print('Cached profile: ${profile?.displayName}');
  print('Cached email (should be empty): "${profile?.email}"');

  // --- Save user preferences (non-sensitive, shared_preferences) ---
  print('\n=== Setting Preferences ===');
  await storage.preferences.setThemeMode('dark');
  await storage.preferences.setLocale('en_US');
  await storage.preferences.setNotificationsEnabled(true);
  await storage.preferences.setFontSize(16.0);
  await storage.preferences.setOnboardingComplete(true);

  final theme = await storage.preferences.getThemeMode();
  final locale = await storage.preferences.getLocale();
  final fontSize = await storage.preferences.getFontSize();
  print('Theme: $theme, Locale: $locale, Font size: $fontSize');

  // --- Cache app configuration ---
  print('\n=== Caching App Configuration ===');
  final config = AppConfiguration(
    apiBaseUrl: 'https://api.example.com/v2',
    cacheExpirationMinutes: 15,
    maintenanceMode: false,
    minimumAppVersion: '2.1.0',
    featureFlags: {
      'dark_mode': true,
      'beta_features': false,
      'new_dashboard': true,
    },
    lastFetched: DateTime.now(),
  );
  await storage.saveAppConfiguration(config);

  final cachedConfig = await storage.getAppConfiguration();
  print('API Base URL: ${cachedConfig?.apiBaseUrl}');
  print('Feature flags: ${cachedConfig?.featureFlags}');
  print('Config expired: ${cachedConfig?.isExpired()}');

  // --- Cache arbitrary content ---
  print('\n=== Caching Content ===');
  await storage.cache.cacheJson(
    'feed_page_1',
    {
      'items': [
        {'id': 1, 'title': 'First Post'},
        {'id': 2, 'title': 'Second Post'},
      ],
      'totalPages': 5,
    },
    ttl: const Duration(minutes: 10),
  );

  final feedData = await storage.cache.getCachedJson('feed_page_1');
  print('Cached feed data: $feedData');

  await storage.cache.cacheJsonList(
    'notifications',
    [
      {'id': 'n1', 'message': 'Welcome!', 'read': false},
      {'id': 'n2', 'message': 'New feature available', 'read': true},
    ],
    ttl: const Duration(minutes: 5),
  );

  final notifications = await storage.cache.getCachedJsonList('notifications');
  print('Cached notifications: ${notifications?.length} items');

  // --- Cache maintenance ---
  print('\n=== Cache Maintenance ===');
  final cacheKeys = await storage.cache.getCacheKeys();
  print('Cache keys: $cacheKeys');

  final purged = await storage.purgeExpiredCache();
  print('Purged $purged expired entries');

  // --- Demonstrate security separation ---
  print('\n=== Security Verification ===');
  print('Access token is in SECURE storage (encrypted, platform-native)');
  print('Refresh token is in SECURE storage (encrypted, platform-native)');
  print('User preferences are in SharedPreferences (non-sensitive only)');
  print('Cached content is in SharedPreferences (non-sensitive only)');
  print('Email/PII is NOT persisted in cache');

  // --- Simulate logout ---
  print('\n=== Simulating Logout ===');
  await storage.onUserLogout();

  final isAuthAfterLogout = await storage.isAuthenticated();
  print('Is authenticated after logout: $isAuthAfterLogout');

  final profileAfterLogout = await storage.getUserProfile();
  print('Profile after logout: $profileAfterLogout');

  // Preferences survive logout
  final themeAfterLogout = await storage.preferences.getThemeMode();
  print('Theme after logout (preserved): $themeAfterLogout');

  print('\n=== Done ===');
}